#!/bin/bash&#10;set -e&#10;&#10;echo "Setting up My Voice..."&#10;&#10;MYVOICE_DIR="/home/jessepaul/my-voice"&#10;CONFIG_DIR="/home/jessepaul/.config/my-voice"&#10;SYSTEMD_DIR="/home/jessepaul/.config/systemd/user"&#10;DESKTOP_DIR="/home/jessepaul/.local/share/applications"&#10;&#10;pip install --user -r "$MYVOICE_DIR/requirements.txt"&#10;&#10;mkdir -p "$CONFIG_DIR" "$SYSTEMD_DIR" "$DESKTOP_DIR"&#10;&#10;cp "$MYVOICE_DIR/configs/config.toml" "$CONFIG_DIR/"&#10;cp "$MYVOICE_DIR/configs/my-voice.service" "$SYSTEMD_DIR/"&#10;&#10;systemctl --user daemon-reload&#10;systemctl --user enable --now my-voice.service&#10;&#10;cat > "$DESKTOP_DIR/com.myvoice.puck.desktop" << EOF&#10;[Desktop Entry]&#10;Version=1.0&#10;Type=Application&#10;Name=My Voice Puck&#10;Comment=Lightweight voice assistant puck UI&#10;Exec=python3 $MYVOICE_DIR/src/ui/my_voice_puck.py&#10;Icon=voice-chat-symbolic&#10;Terminal=false&#10;Categories=Utility;AudioVideo;&#10;StartupNotify=true&#10;EOF&#10;&#10;echo "Setup complete!"&#10;echo "Service: systemctl --user status my-voice.service"&#10;echo "Launch puck from applications menu or python3 src/ui/my_voice_puck.py"&#10;echo "Hotkeys: Super+W (STT), Super+R (TTS) via GNOME settings"